    // tags), we copy S = V = severity when severity is defined. Consumers like
    // `fieldsToNotice` look at V then S so this matches.
    const set = (tag, value) => {
        if (typeof value === 'string')
            out.set(tag, value);
    };
    set('S', msg.severity);
    set('V', msg.severity);
    set('C', msg.code);
    set('M', msg.message);
    set('D', msg.detail);
    set('H', msg.hint);
    set('P', msg.position);
    set('p', msg.internalPosition);
    set('q', msg.internalQuery);
    set('W', msg.where);
    set('s', msg.schema);
    set('t', msg.table);
    set('c', msg.column);
    set('d', msg.dataType);
